import json
import logging

def fix_pyre_errors(json_str):
    if not json_str.strip(): return
    try:
        errors = json.loads(json_str)
        fixes: dict[str, set[int]] = {}
        for err in errors:
            path = str(err.get('path', ''))
            line = err.get('startLine')
            if path and line:
                if path not in fixes:
                    fixes[path] = set()
                fixes[path].add(int(line))
        
        for path, lines in fixes.items():
            try:
                with open(path, 'r', encoding='utf-8') as f:
                    content = f.read().splitlines()
                
                sorted_lines = sorted(lines, reverse=True)
                for l in sorted_lines:
                    idx = l - 1
                    if 0 <= idx < len(content):
                        # Add # type: ignore if not already present
                        if '# type: ignore' not in content[idx]:
                            content[idx] = content[idx] + '  # type: ignore'
                
                with open(path, 'w', encoding='utf-8') as f:
                    f.write('\n'.join(content) + '\n')
            except Exception as e:
                print(f"Failed {path}: {e}")
    except Exception as e:
        print(f"JSON parsing error: {e}")

